import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Eye, EyeOff, UserPlus } from 'lucide-react';

const RegisterPage = () => {
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  
  const { register } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!formData.name || !formData.email || !formData.password) {
      toast.error('Please fill in all fields');
      return;
    }

    setLoading(true);
    try {
      await register(formData);
      toast.success('Account created successfully!');
      navigate('/login');
    } catch (error) {
      toast.error(error.response?.data?.detail || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-[85vh] w-full flex flex-col items-center justify-center p-6 reveal-node">
      {/* Ambient Glow */}
      <div className="absolute -top-32 -right-32 w-64 h-64" style={{ background: 'var(--accent-glow)', borderRadius: '50%', filter: 'blur(80px)', opacity: 0.5 }} />
      
      {/* Register Card */}
      <div className="w-full max-w-md vault-card" style={{ padding: '2.5rem' }}>
        {/* Header */}
        <div className="text-center mb-10">
          <div className="flex justify-center mb-4" style={{ color: 'var(--accent-primary)' }}>
            <UserPlus size={42} className="animate-pulse" />
          </div>
          <h1 className="text-3xl font-light tracking-tight mb-2" style={{ color: 'var(--text-primary)' }}>
            Initialize Node
          </h1>
          <p className="text-xs uppercase tracking-[0.25em]" style={{ color: 'var(--text-muted)' }}>
            Create your identity
          </p>
        </div>
        
        <form onSubmit={handleSubmit} className="space-y-5">
          {/* Name Field */}
          <div className="space-y-2">
            <label className="flex items-center gap-2 text-xs font-bold uppercase tracking-widest ml-1" style={{ color: 'var(--accent-primary)' }}>
              <span>Full Identity</span>
            </label>
            <input 
                type="text"
                placeholder="John Doe"
                value={formData.name}
                onChange={(e) => setFormData({...formData, name: e.target.value})}
                className="cyber-input"
                style={{ 
                  backgroundColor: 'var(--input-bg)',
                  borderColor: 'var(--input-border)',
                  color: 'var(--text-primary)'
                }}
                required
            />
          </div>
          
          {/* Email Field */}
          <div className="space-y-2">
            <label className="flex items-center gap-2 text-xs font-bold uppercase tracking-widest ml-1" style={{ color: 'var(--accent-primary)' }}>
              <span>Registry Email</span>
            </label>
            <input 
                type="email"
                placeholder="operator@finify.ai"
                value={formData.email}
                onChange={(e) => setFormData({...formData, email: e.target.value})}
                className="cyber-input"
                style={{ 
                  backgroundColor: 'var(--input-bg)',
                  borderColor: 'var(--input-border)',
                  color: 'var(--text-primary)'
                }}
                required
            />
          </div>
          
          {/* Password Field */}
          <div className="space-y-2">
            <label className="flex items-center gap-2 text-xs font-bold uppercase tracking-widest ml-1" style={{ color: 'var(--accent-primary)' }}>
              <span>Security Key</span>
            </label>
            <div className="relative">
              <input 
                  type={showPassword ? "text" : "password"}
                  placeholder="••••••••"
                  value={formData.password}
                  onChange={(e) => setFormData({...formData, password: e.target.value})}
                  className="cyber-input pr-12"
                  style={{ 
                    backgroundColor: 'var(--input-bg)',
                    borderColor: 'var(--input-border)',
                    color: 'var(--text-primary)'
                  }}
                  required
              />
              <button 
                type="button" 
                onClick={() => setShowPassword(!showPassword)} 
                className="absolute right-4 top-1/2 -translate-y-1/2 cursor-pointer"
                style={{ color: 'var(--text-muted)' }}
              >
                {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
          </div>
          
          {/* Submit Button */}
          <button 
            type="submit" 
            className="cyber-btn mt-6 w-full"
            style={{ 
              backgroundImage: 'linear-gradient(135deg, var(--accent-secondary), var(--accent-primary))' 
            }}
            disabled={loading}
          >
            {loading ? 'INITIALIZING...' : 'Initialize New Identity'}
          </button>
        </form>
        
        {/* Footer */}
        <div className="mt-10 pt-8 border-t text-center" style={{ borderColor: 'var(--surface-border)' }}>
          <p className="text-xs uppercase tracking-[0.25em]" style={{ color: 'var(--text-muted)' }}>
            Identity already exists?{' '}
            <Link to="/login" style={{ color: 'var(--accent-primary)' }} className="hover:underline">
              Access Gate
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
};
export default RegisterPage;
